// Conceptual representation of metrics
let startTime = Date.now();

// Send request over network
fetch('https://api.example.com/data')
  .then(response => {
     let firstByteTime = Date.now();
     let latency = firstByteTime - startTime;
     console.log(`Latency (TTFB): ${latency}ms`);
     return response.json();
  })
  .then(data => {
     let lastByteTime = Date.now();
     let responseTime = lastByteTime - startTime;
     console.log(`Total Response Time: ${responseTime}ms`);
  });
